content: <!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8">
    <title>Survival Road Game</title>
    <meta name="description" content="Survival Road Game - Stay on the road as long as you can!">
    <script src="https://aframe.io/releases/1.4.0/aframe.min.js"></script>
    <style>
      body {
        margin: 0;
        overflow: hidden;
        font-family: Arial, sans-serif;
      }
      #info {
        position: absolute;
        top: 10px;
        left: 10px;
        color: white;
        background-color: rgba(0, 0, 0, 0.5);
        padding: 10px;
        border-radius: 5px;
        font-size: 18px;
        z-index: 100;
      }
      #gameOver {
        position: absolute;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        color: white;
        background-color: rgba(0, 0, 0, 0.8);
        padding: 20px;
        border-radius: 10px;
        font-size: 24px;
        text-align: center;
        display: none;
        z-index: 100;
      }
      button {
        background-color: #4CAF50;
        border: none;
        color: white;
        padding: 10px 20px;
        text-align: center;
        text-decoration: none;
        display: inline-block;
        font-size: 16px;
        margin: 10px 2px;
        cursor: pointer;
        border-radius: 5px;
      }
    </style>
  </head>
  <body>
    <div id="info">Time: <span id="time">0</span>s</div>
    <div id="gameOver">
      <h2>Game Over!</h2>
      <p>You survived for <span id="finalTime">0</span> seconds.</p>
      <button onclick="restartGame()">Play Again</button>
    </div>
    <a-scene id="scene">
      <a-assets>
        <img id="roadTexture" src="https://cdn.aframe.io/360-image-gallery-boilerplate/img/sechelt.jpg" crossorigin="anonymous">
      </a-assets>

      <a-entity id="cameraRig" position="0 1.6 0">
        <a-camera id="camera" look-controls="pointerLockEnabled: true"></a-camera>
      </a-entity>

      <a-entity id="car" position="0 0.5 -5" rotation="0 0 0">
        <a-box color="#FF5733" width="1" height="0.5" depth="2" position="0 0 0"></a-box>
      </a-entity>

      <a-plane id="road" position="0 0 0" rotation="-90 0 0" width="20" height="100" color="#333333" repeat="10 1"></a-plane>

      <a-sky color="#87CEEB"></a-sky>

      <a-light type="ambient" color="#BBB" intensity="0.3"></a-light>
      <a-light type="directional" color="#FFF" intensity="0.7" position="-1 2 1"></a-light>
    </a-scene>

    <script>
      let gameActive = true;
      let time = 0;
      let roadSegments = [];
      const segmentLength = 10;
      const roadWidth = 20;

      // Initialize road segments
      function initRoad() {
        const road = document.getElementById('road');
        for (let z = 0; z < 100; z += segmentLength) {
          const segment = document.createElement('a-entity');
          segment.setAttribute('geometry', {
            primitive: 'plane',
            width: roadWidth,
            height: segmentLength
          });
          segment.setAttribute('position', {x: 0, y: 0, z: z - 50});
          segment.setAttribute('rotation', '-90 0 0');
          segment.setAttribute('material', 'color: #333333; side: double');
          segment.setAttribute('class', 'road-segment');
          road.appendChild(segment);
          roadSegments.push(segment);
        }
      }

      // Update game state
      function updateGame() {
        if (!gameActive) return;

        time += 0.1;
        document.getElementById('time').textContent = time.toFixed(1);

        // Move car based on camera rotation
        const camera = document.getElementById('camera');
        const car = document.getElementById('car');
        const rotation = camera.getAttribute('rotation');

        // Simple movement: car moves forward and turns based on camera rotation
        const moveSpeed = 0.2;
        const turnSpeed = 0.05;

        // Get current position and rotation
        const pos = car.getAttribute('position');
        const carRot = car.getAttribute('rotation');

        // Turn car based on camera's y rotation
        const targetYRot = rotation.y;
        car.setAttribute('rotation', {
          x: carRot.x,
          y: carRot.y + (targetYRot - carRot.y) * turnSpeed,
          z: carRot.z
        });

        // Move car forward
        const rad = carRot.y * Math.PI / 180;
        pos.x += Math.sin(rad) * moveSpeed;
        pos.z += Math.cos(rad) * moveSpeed;
        car.setAttribute('position', pos);

        // Randomly remove road segments
        if (Math.random() < 0.02) {
          removeRandomRoadSegment();
        }

        // Check if car is off the road
        if (Math.abs(pos.x) > roadWidth/2 - 0.5) {
          endGame();
        }

        requestAnimationFrame(updateGame);
      }

      function removeRandomRoadSegment() {
        if (roadSegments.length === 0) return;

        const index = Math.floor(Math.random() * roadSegments.length);
        const segment = roadSegments[index];

        // Only remove segments that are behind the car
        const carPos = document.getElementById('car').getAttribute('position');
        const segPos = segment.getAttribute('position');

        if (segPos.z < carPos.z - 5) {
          segment.parentNode.removeChild(segment);
          roadSegments.splice(index, 1);
        }
      }

      function endGame() {
        gameActive = false;
        document.getElementById('finalTime').textContent = time.toFixed(1);
        document.getElementById('gameOver').style.display = 'block';
      }

      function restartGame() {
        location.reload();
      }

      // Initialize and start game
      window.addEventListener('load', function() {
        initRoad();
        updateGame();
      });
    </script>
  </body>
</html>
